{
  "name": "MO HealthNet",
  "eligibility": {
    "age": 65,
    "income_limits": "For MO HealthNet for the Aged, Blind, and Disabled (MHABD) Non-Spend down: Individual Elderly/Disabled $860 monthly, Blind $1,012 monthly; Couple Elderly/Disabled $1,166 monthly, Blind $1,372 monthly. Spend down option reduces income to these limits via medical expenses. Home and Community Based Waiver: $1,311 monthly individual. Nursing home vendor coverage requires all income toward care cost (no fixed limit like HCBS waivers at $1,690 monthly in 2025). Limits from 2019 chart; check current FPL adjustments as they vary by household size for some categories but fixed for ABD elderly.[8][5][4]",
    "asset_limits": "Individual Elderly/Disabled or Blind: $3,000; Couple: $6,000. Exemptions typically include primary home (with equity limits, consult elder law attorney for 55+ with real property), one vehicle, personal belongings, burial plots. What counts: cash, bank accounts, investments, second vehicles/properties.[8][6]",
    "other_requirements": ["Missouri resident", "U.S. citizen or qualified immigrant", "For long-term care (nursing home, HCBS waivers): Nursing Facility Level of Care (NFLOC) based on ADLs/IADLs assessment", "Blind or disabled status may have separate criteria", "Functional need for regular ABD Medicaid long-term services (ADLs assessment, NFLOC not always required)"]
  },
  "benefits": {
    "type": "service",
    "value": "Basic healthcare (physician visits, prescriptions, ER, short-term hospital); long-term care via ABD: nursing home (covers costs beyond patient income), HCBS waivers (home health, personal care, adult day, home modifications), non-medical personal needs; supplemental nursing care. Specifics depend on NFLOC assessment; no fixed hours/dollars stated, varies by need.[2][4][5]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Online: https://mydss.mo.gov/healthcare/apply", "Phone: 855-373-9994 or 1-800-318-2596 via HealthCare.gov transfer", "Paper: Download from myDSS.mo.gov and mail", "In-person: Local Family Support Division offices or nursing home assistance"],
    "processing_time": "Not specified in sources; typically 45-90 days for long-term care due to assessments",
    "waitlist": "Possible for HCBS waivers due to limited slots (not detailed by region)",
    "forms": ["MO HealthNet Application", "Supplemental Form (required if 65+, blind/disabled, SSI recipient, nursing facility resident, Medicare/VA)"],
    "documents": ["Proof of income (pay stubs, SSI awards)", "Proof of assets (bank statements)", "ID (birth certificate, Social Security card)", "Proof of residency", "Medical records/disability proof for NFLOC", "Medicare/VA info if applicable"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available to Missouri residents statewide",
    "regional_variations": "Processing/wait times may vary by local Family Support Division office; HCBS waiver slots limited regionally",
    "offices_or_providers": ["Local Department of Social Services Family Support Division offices"]
  },
  "official_source": "https://mydss.mo.gov/healthcare/apply",
  "gotchas": ["Nursing home income rules differ (all income to care, no $1,690 cap like HCBS); spend down via medical bills for over-limit income; home equity limits for 55+ (consult attorney); HCBS waivers have waitlists; must complete Supplemental Form or risk denial; ABD requires disability/age 65+ even for basic coverage.[4][5][8][1]"],
  "data_shape_notes": "Fixed asset/income limits for ABD elderly (not scaling by household size beyond couple); separate tracks for nursing home vs HCBS (different income rules); NFLOC mandatory for long-term care; spend down pathway unique for medically needy"
}

{
  "name": "Missouri State Health Insurance Assistance Program (SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; open to all Medicare-eligible individuals, their families, and caregivers, including those with limited incomes[1][2][4]",
    "asset_limits": "No asset limits or tests apply[1][2][4]",
    "other_requirements": ["Must be eligible for Medicare (typically age 65+ or under 65 with certain disabilities), or be a family member/caregiver of a Medicare beneficiary[1][2][4]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free, unbiased, confidential one-on-one counseling and education on Medicare options (Parts A, B, C, D, Medigap); help choosing plans; assistance determining eligibility for Low-Income Subsidy (Extra Help) and Medicare Savings Programs; help with appeals, claims, and reporting fraud via Senior Medicare Patrol (SMP); group presentations and outreach; no sales or fees[1][2][4]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-800-390-3330[1][3][5][6]", "Website: https://www.missouriship.org (for counseling requests and info)[4][6]", "In-person: Through local volunteer counselors and community partners throughout Missouri[4]", "No specific online form or mail application mentioned; contact initiates service"],
    "processing_time": "No formal processing; counseling available throughout the year upon contact, though one-on-one may require scheduling[1][4]",
    "waitlist": null,
    "forms": ["No specific forms required for SHIP counseling; for related programs like Low-Income Subsidy or Medicare Savings, counselors assist with applications (e.g., via SSA or state forms)[1][2]"],
    "documents": ["Medicare card, current prescriptions/drug list, income info (if applying for subsidies), insurance details; prepare questions about plans[1][2][4]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available to all Missouri Medicare beneficiaries[1][4][5]",
    "regional_variations": "Delivered via local volunteer counselors and community partners (e.g., Atchison County Health Department); no differences in services, but local access points vary[3][4]",
    "offices_or_providers": ["Main office: 601 W Nifong Blvd Suite 3A, Columbia, MO 65203-6804[5]", "Local partners statewide, e.g., Atchison County Health Dept (421 Main, Tarkio, MO 64491)[3]"]
  },
  "official_source": "https://www.missouriship.org[4]",
  "gotchas": ["Not an insurance seller—does not enroll you directly but guides you; rebranded from Missouri CLAIM in 2023, so search old name may confuse[1][4]", "Services are year-round but emphasize Medicare Open Enrollment (Oct 15-Dec 7); review plans annually[1][3]", "For actual subsidies like Extra Help, separate applications needed post-counseling[1][2]", "Targeted at Medicare eligibles—does not provide direct healthcare or payments[2][4]"],
  "data_shape_notes": "no income/asset test; counseling-only service via statewide volunteer network; focuses on Medicare navigation and subsidy eligibility assistance rather than direct financial aid"
}

{
