    "asset_limits": "No asset limits mentioned in Missouri CSFP guidelines.",
    "other_requirements": ["Missouri resident.", "Verification of age (e.g., birth certificate, driver's license, passport).", "Income verification via self-declaration.", "Residency verification (e.g., utility bill, driver's license, SSA document)."][1][2]
  },
  "benefits": {
    "type": "in_kind",
    "value": "Monthly package of nutritious USDA commodity foods to supplement diets. Specific foods not detailed in sources, but aimed at improving health of low-income seniors 60+.",
    "varies_by": "fixed"
  },
  "application": {
    "methods": ["Contact local agencies or providers (e.g., Platte County Seniors: 816-270-4100 for Platte County).[6]", "Visit state site for local distributors: https://health.mo.gov/living/wellness/nutrition/foodprograms/csfp/.[2]", "In-person at local food banks or senior centers distributing CSFP (statewide via local agencies)."],
    "processing_time": "Not specified in sources.",
    "waitlist": "Program limited by funding; may have waitlists at local sites as it serves only as many as funding allows.",
    "forms": ["No specific form name/number listed; application via local agency certification process."],
    "documents": ["Age: Birth certificate, driver's license, passport, etc.", "Income: Self-declaration.", "Residency: Utility bill, driver's license, SSA document, etc."][1][2]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available statewide in Missouri to eligible seniors 60+.",
    "regional_variations": "Administered through local agencies/food banks/senior centers; contact local provider for pickup or delivery. Variations in availability, wait times, and distribution sites by region (e.g., Platte County via Platte Seniors).[6]",
    "offices_or_providers": ["Local distributors listed via https://health.mo.gov/living/wellness/nutrition/foodprograms/csfp/ (e.g., Southeast Missouri Food Bank, Platte County Senior Services)."][2][3][6]
