  "official_source": "https://health.mo.gov/living/wellness/nutrition/foodprograms/csfp/[2]",
  "gotchas": ["Limited by funding; not all eligible seniors can be served—check local availability and waitlists.", "Cannot participate in both CSFP and WIC simultaneously.", "Missouri uses 150% FPL (higher than federal max of 130% in some states).", "Women/infants/children only grandfathered if certified before Feb 7, 2014—no new certifications.", "Income is household-based, even for seniors living alone."][1][2][4][7],
  "data_shape_notes": "State-specific income at 150% FPL with household size table; no asset test; distributed via local agencies with potential funding/waitlist limits; elderly-only in Missouri (no new women/infants/children)."
}

{
  "name": "Senior Community Service Employment Program (SCSEP)",
  "eligibility": {
    "age": 55,
    "income_limits": "Family income must not exceed 125% of the federal poverty level. Exact dollar amounts vary annually and by household size; families must check current federal poverty guidelines as specific 2026 figures are not listed in sources. Excluded income includes: Social Security Disability Income, 25% of Social Security Income, unemployment benefits, SNAP benefits, housing benefits, and certain veterans' payments[1][2][3][7].",
    "asset_limits": "No asset limits mentioned in sources[1][2][3].",
    "other_requirements": ["Unemployed at time of application[1][2][3][7]", "U.S. citizen or eligible non-citizen (inferred from federal program standards, not explicitly stated for MO)", "Priority given to veterans and qualified spouses, individuals over 65, those with disabilities, low literacy or limited English proficiency, rural residents, homeless or at-risk, low employment prospects, or prior American Job Center users[3]"]
  },
  "benefits": {
    "type": "employment",
    "value": "Part-time community service work-based job training (average 20 hours/week at highest of federal, state, or local minimum wage); Individual Employment Plan (updated every 6 months); on-the-job skill training; job placement assistance (resume help, interview coaching, job search); annual health screening; supportive services (benefit application assistance, access to local resources for basic needs); placements at non-profits or public agencies like schools, hospitals, senior centers[1][2][3][4][5].",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: Missouri Department of Health and Senior Services (contact via main site) or MERS/Goodwill SCSEP at 1-888-651-4177[1][5][7]", "Online: Request application via MERS Goodwill form (eastern/central/southeast MO)[5]", "In-person: Local providers like MERS Goodwill offices in St. Louis and surrounding counties, southeast MO[5][7]", "Mail: Not specified, but applications can be requested via phone/online[5][7]"],
    "processing_time": "Not specified in sources",
    "waitlist": "Likely due to availability in many counties (not statewide); regional variations implied but not detailed[1]",
    "forms": ["Individual Employment Plan (created after enrollment, updated every 6 months); no specific pre-application form name/number listed[1][4]"],
    "documents": ["Proof of age, unemployment status, and income (to verify <125% FPL, noting exclusions); sources do not list exhaustive checklist[1][2]"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Available in many counties throughout Missouri, not all; focused in eastern, central, southeast MO via providers like MERS Goodwill; also St. Louis and surrounding[1][5][6][7]",
    "regional_variations": "Administered by sub-grantees like Missouri DHSS statewide oversight, MERS Goodwill in specific regions (e.g., St. Louis, southeast MO); different providers may handle intake/job placement[1][2][5][7]",
    "offices_or_providers": ["Missouri Department of Health and Senior Services, 912 Wildwood Drive, Jefferson City, MO 65109[2]", "MERS Goodwill (eastern, central, southeast MO, St. Louis areas)[5][7]"]
  },
  "official_source": "https://health.mo.gov/seniors/senioremployment/",
  "gotchas": ["Income exclusions are specific (e.g., only 25% of SS income excluded, full SSDI excluded)—families must calculate carefully[1]", "Not available in all MO counties; check local availability[1][5]", "Must be unemployed at application; program emphasizes transition to unsubsidized jobs with required job search[3][4]", "Priority tiers affect entry, not benefits[3]", "Part-time training wage only, not full employment or other benefits like healthcare[1][3]"],
  "data_shape_notes": "Income test at 125% FPL with specific exclusions; county-restricted availability via sub-grantees like MERS Goodwill; priority tiers for enrollment; not statewide"
}

