{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available to any resident regardless of financial status.",
    "asset_limits": "No asset limits; no financial tests apply.",
    "other_requirements": ["Must be a resident of a long-term care facility in Missouri, such as nursing homes, residential care facilities, assisted living, skilled care nursing homes, residential care homes, or veteran homes."]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Advocacy services including identifying, investigating, and resolving complaints related to health, safety, welfare, and rights; providing information on long-term services and supports; representing residents before governmental agencies; seeking administrative, legal, or other remedies; regular facility visits by trained volunteers; education on resident rights; mediation and problem-solving to improve quality of life.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: (800) 309-3282 (toll-free) or (573) 526-0727 (local)", "Email: LTCOmbudsman@health.mo.gov", "Contact regional Area Agency on Aging (AAA) or service provider for local assistance", "In-person: Through local ombudsman programs operated by AAAs"],
    "processing_time": "Immediate assistance upon contact; no formal processing as it is complaint-driven advocacy, not an enrollment program.",
    "waitlist": null,
    "forms": ["No specific application forms required; contact to report issues or request services."],
    "documents": ["No documents needed to request services; provide details of the resident's situation, facility name, and complaint if applicable."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Services provided through regional networks covering participating counties; available to residents in facilities statewide.",
    "regional_variations": "Operated by 10 Area Agencies on Aging (AAAs) or their service providers with regional ombudsman coordinators recruiting volunteers and handling local services; availability depends on local volunteer coverage.",
    "offices_or_providers": ["State Office: Missouri Department of Health and Senior Services, Division of Senior and Disability Services; Regional: Area Agencies on Aging (AAAs) statewide."]
  },
  "official_source": "https://health.mo.gov/seniors/ombudsman/",
  "gotchas": ["This is not a financial aid, healthcare, or housing program—it's purely advocacy and complaint resolution for residents already in facilities; families cannot 'apply' for placement via this program; services are for residents, not prospective ones; relies on volunteers, so response may vary by local coverage; not for facility staff or volunteers to use personally due to conflict of interest rules."],
