}

{
  "name": "No Tax on Social Security Benefits",
  "eligibility": {
    "age": 62,
    "income_limits": "For tax years 2023 and prior: Missouri adjusted gross income must be $85,000 or less for single, head of household, or qualifying widow(er); $100,000 or less for married filing combined; $85,000 or less for married filing separately to qualify for full deduction. For tax years beginning on or after January 1, 2024: No income limits; 100% of social security benefits for individuals age 62 or older (and 100% of social security disability benefits) are not taxed, as long as included in federal adjusted gross income under IRC §86.[1]",
    "asset_limits": "No asset limits apply.",
    "other_requirements": ["Benefits must be included in federal adjusted gross income under IRC §86 (for post-2024).", "Applies to social security benefits or social security disability benefits.[1]"]
  },
  "benefits": {
    "type": "financial",
    "value": "100% exemption from Missouri state income tax on social security benefits (or social security disability benefits). No specific dollar amount, as it depends on the individual's benefit amount; full exemption regardless of benefit size once eligible.[1][4]",
    "varies_by": "fixed"
  },
  "application": {
    "methods": ["Claim the deduction when filing Missouri state income tax return (MO-1040). No separate application; handled through standard tax filing process. Contact Missouri Department of Revenue for tax assistance: (573) 751-3505 or visit dor.mo.gov.[1]"],
    "processing_time": "Determined upon filing and processing of annual Missouri state income tax return; typically aligns with standard tax refund/processing timelines (6-8 weeks for e-filed returns).",
    "waitlist": null,
    "forms": ["MO-1040 (Missouri Individual Income Tax Return); deduction claimed directly on form.[1]"],
    "documents": ["Federal tax return (Form 1040) showing social security benefits under IRC §86.", "Proof of age if needed (e.g., birth certificate, Social Security statements).", "Missouri adjusted gross income calculations for pre-2024 claims.[1]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; applies to all Missouri state income tax filers.",
    "regional_variations": null,
    "offices_or_providers": []
  },
  "official_source": "https://dor.mo.gov/faq/taxation/individual/pension.html",
  "gotchas": ["Pre-2024 income limits still apply if filing for those years; exceeds limits means partial or no deduction.[1]", "Deduction only for benefits included in federal AGI under IRC §86; not all benefits qualify federally.[1][7]", "Public pension deductions reduced if also claiming social security deduction.[1]", "Federal taxes may still apply (up to 85% taxable based on combined income).[7]", "Not a cash benefit or service; only affects state income tax liability when filing.[4]"],
  "data_shape_notes": "Tax deduction claimed on annual state income tax return, not a standalone program with application; changed in 2024 to full exemption without income limits.[1][2][4]"
}
